package com.lambda.Objects;public class Table {    private int table_id;    private int capacity;    private String location;    private boolean is_available;    public int getTable_id() {        return table_id;    }    public void setTable_id(int table_id) {        this.table_id = table_id;    }    public int getCapacity() {        return capacity;    }    public void setCapacity(int capacity) {        this.capacity = capacity;    }    public String getLocation() {        return location;    }    public void setLocation(String location) {        this.location = location;    }    public boolean isAvailable() {        return is_available;    }    public void setAvailable(boolean is_available) {        this.is_available = is_available;    }}